// Inputs expected:
// Input 1: Fetch competitor intel
// Input 2: Fetch Indication Heatmap
// Input 3: Fetch last 24h signal
// Input 4: Fetch last 7day signal

// Pull data from the named nodes (make sure names match exactly)
const signals24h      = $('Fetch last 24h signal').all().map(i => i.json);
const trend7d         = $('Fetch last 7day signal').all().map(i => i.json);
const competitorIntel = $('Fetch competitor intel').all().map(i => i.json);
const heatmap         = $('Fetch Indication Heatmap').all().map(i => i.json);

const today = new Date().toISOString().slice(0, 10);
const now   = new Date().toISOString();

// ─── 24h Segmentation (no impact_score assumed) ───────────
const highSignals = signals24h.filter(s =>
  String(s.impact_level || '').toUpperCase() === 'HIGH'
);
const medSignals = signals24h.filter(s =>
  String(s.impact_level || '').toUpperCase() === 'MED'
);
const lowSignals = signals24h.filter(s =>
  String(s.impact_level || '').toUpperCase() === 'LOW'
);
const newSignals     = signals24h.filter(s => s.signal_status === 'NEW');
const updatedSignals = signals24h.filter(s => s.signal_status === 'UPDATE');
const competitorHits = signals24h.filter(s => s.competitor_flag);

// If you don't have impact_score in DB yet, just set simple metrics
const avgScore = 0;
const maxScore = 0;
const topSignal = signals24h[0] || null;

// ─── 7d Trend Analysis ─────────────────────────────────────
const todayData     = trend7d.filter(t => t.signal_date === today);
const yesterdayDate = new Date(Date.now() - 86400000).toISOString().slice(0, 10);
const yesterdayData = trend7d.filter(t => t.signal_date === yesterdayDate);

const todayTotal     = todayData.reduce((s, t) => s + parseInt(t.count || 0, 10), 0);
const yesterdayTotal = yesterdayData.reduce((s, t) => s + parseInt(t.count || 0, 10), 0);
const trendDelta     = todayTotal - yesterdayTotal;
const trendPct       = yesterdayTotal > 0
  ? ((trendDelta / yesterdayTotal) * 100).toFixed(1)
  : 'N/A';
const trendArrow     = trendDelta > 0 ? '📈' : trendDelta < 0 ? '📉' : '➡️';

// 7-day rolling high count
const weekHighCount = trend7d
  .filter(t => String(t.impact_level || '').toUpperCase() === 'HIGH')
  .reduce((s, t) => s + parseInt(t.count || 0, 10), 0);

// ─── Signal Type Breakdown ─────────────────────────────────
const typeBreakdown = {};
signals24h.forEach(s => {
  const t = s.signal_type || 'unknown';
  typeBreakdown[t] = (typeBreakdown[t] || 0) + 1;
});
const typeBreakdownStr = Object.entries(typeBreakdown)
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => `${k}: ${v}`)
  .join(' | ');

// ─── Source Breakdown ──────────────────────────────────────
const sourceBreakdown = {};
signals24h.forEach(s => {
  const src = s.source || 'unknown';
  sourceBreakdown[src] = (sourceBreakdown[src] || 0) + 1;
});
const sourceBreakdownStr = Object.entries(sourceBreakdown)
  .sort((a, b) => b[1] - a[1])
  .map(([k, v]) => `${k}(${v})`)
  .join(', ');

// ─── Top Drugs by Frequency ────────────────────────────────
const drugFreq = {};
signals24h.forEach(s => {
  const d = s.key_drug || s.drug_name || 'Unknown';
  drugFreq[d] = (drugFreq[d] || 0) + 1;
});
const topDrugs = Object.entries(drugFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([d, c]) => `*${d}* (${c})`)
  .join(', ');

// ─── Risk Assessment (counts only) ─────────────────────────
let riskLevel = 'LOW';
let riskReason = 'No urgent competitive threats';
if (highSignals.length >= 5 || competitorHits.length >= 3) {
  riskLevel = 'CRITICAL';
  riskReason = 'Multiple HIGH signals + significant competitor activity';
} else if (highSignals.length >= 2 || competitorHits.length >= 1) {
  riskLevel = 'ELEVATED';
  riskReason = 'Competitor signals or multiple HIGH impact events detected';
} else if (highSignals.length === 1) {
  riskLevel = 'MODERATE';
  riskReason = 'Single HIGH impact signal requires monitoring';
}

const riskEmoji = {
  CRITICAL: '🔴', ELEVATED: '🟠', MODERATE: '🟡', LOW: '🟢'
}[riskLevel];

// ─── Build Context String for AI ──────────────────────────
const aiContextLines = signals24h.slice(0, 10).map((s, i) =>
  `${i + 1}. [${s.impact_level}] ${s.key_drug || s.drug_name || 'Unknown'} | ` +
  `${s.key_indication || 'Unknown'} | ${s.sponsor || 'Unknown'} | ` +
  `${s.signal_type || 'unknown'} | ${s.ai_summary || 'No summary'}`
).join('\n');

// ─── Build Indication Heatmap String ──────────────────────
const heatmapStr = heatmap.slice(0, 6).map(h =>
  `${h.indication}: ${h.total_signals} signals (H:${h.high_count} M:${h.med_count})`
).join('\n');

// ─── Competitor Intel String ───────────────────────────────
const competitorStr = competitorIntel.slice(0, 5).map((c, i) =>
  `${i + 1}. ${c.key_drug || c.drug_name || 'Unknown'} (${c.sponsor || 'Unknown'}) — ` +
  `${c.key_indication || 'Unknown'} | ${c.signal_count} signals`
).join('\n');

// ─── Digest body for Slack text node ──────────────────────
const digestBody = [
  highSignals.length > 0 ? `🚨 *HIGH IMPACT SIGNALS*\n` + highSignals.map((s, i) => {
    const drug = s.key_drug || s.drug_name || 'Unknown';
    const status = s.signal_status === 'NEW' ? '🆕 NEW' : `🔄 v${s.version || 1}`;
    const rival = s.competitor_flag ? ' ⚠️ COMPETITOR' : '';
    return (
      `*${i+1}. ${drug}* — ${s.key_indication || 'Unknown'} ${status}${rival}\n` +
      `> Sponsor: ${s.sponsor || 'N/A'} | Type: ${s.signal_type || 'unknown'}\n` +
      `> ${s.ai_summary || 'No summary'}\n` +
      `> 🎯 Action: _${s.recommended_action || 'Monitor'}_\n` +
      `> 🔗 ${s.url || 'No URL'}`
    );
  }).join('\n\n') : '',

  medSignals.length > 0 ? `\n🟡 *MED IMPACT SIGNALS (top 5 of ${medSignals.length})*\n` + medSignals.slice(0,5).map((s, i) => {
    const drug = s.key_drug || s.drug_name || 'Unknown';
    const status = s.signal_status === 'NEW' ? '🆕 NEW' : `🔄 v${s.version || 1}`;
    const rival = s.competitor_flag ? ' ⚠️ COMPETITOR' : '';
    return (
      `*${i+1}. ${drug}* — ${s.key_indication || 'Unknown'} ${status}${rival}\n` +
      `> Sponsor: ${s.sponsor || 'N/A'}\n` +
      `> ${s.ai_summary || 'No summary'}\n` +
      `> 🎯 Action: _${s.recommended_action || 'Monitor'}_`
    );
  }).join('\n\n') : '',

  heatmap.length > 0 ? `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🗺️ *Indication Heatmap*\n` + heatmap.slice(0,6).map(h =>
    `• *${h.indication}*: ${h.total_signals} signals (🚨${h.high_count} 🟡${h.med_count}) | competitor: ${h.competitor_signals}`
  ).join('\n') : '',

  competitorIntel.length > 0 ? `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🕵️ *7-Day Competitor Radar*\n` + competitorIntel.slice(0,5).map((c, i) =>
    `${i+1}. *${c.key_drug || c.drug_name}* (${c.sponsor}) — ${c.key_indication} | ${c.signal_count} signals`
  ).join('\n') : '',

  `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`,
  `💊 *Top Drugs:* ${topDrugs || 'N/A'}`,
  `📁 *Signal Types:* ${typeBreakdownStr || 'N/A'}`,
  `🌐 *Sources:* ${sourceBreakdownStr || 'N/A'}`,
  `\n_OncoWatch CI System | ${now}_`
].filter(Boolean).join('\n');

return [{
  json: {
    signals24h,
    highSignals,
    medSignals,
    lowSignals,
    competitorIntel,
    heatmap,
    trend7d,

    today,
    now,
    total24h: signals24h.length,
    highCount: highSignals.length,
    medCount: medSignals.length,
    lowCount: lowSignals.length,
    newCount: newSignals.length,
    updatedCount: updatedSignals.length,
    competitorCount: competitorHits.length,
    avgScore,
    maxScore,
    topSignal,

    trendDelta,
    trendPct,
    trendArrow,
    weekHighCount,

    typeBreakdownStr,
    sourceBreakdownStr,
    topDrugs,

    riskLevel,
    riskReason,
    riskEmoji,

    aiContextLines,
    heatmapStr,
    competitorStr,
    digestBody
  }
}];

const d = $('Compute Analytics').first().json;
const aiResponse = $input.first().json;
const execSummary = aiResponse?.choices?.[0]?.message?.content || 'AI summary unavailable.';

// ─── Safe accessor ────────────────────────────────────────
const safe = (v, fallback = 'N/A') =>
  (v !== null && v !== undefined && String(v).trim() !== '') ? String(v) : fallback;

// ─── Risk color map ───────────────────────────────────────
const riskColor = {
  CRITICAL: '#FF0000',
  ELEVATED: '#FF6600',
  MODERATE: '#FFB300',
  LOW:      '#36A64F'
}[d.riskLevel] || '#36A64F';

// ─── Helper: divider ──────────────────────────────────────
const divider = () => ({ type: 'divider' });

// ─── Helper: signal block ─────────────────────────────────
function signalBlock(s, index) {
  const drug      = safe(s.key_drug || s.drug_name);
  const indication = safe(s.key_indication);
  const sponsor   = safe(s.sponsor);
  const score     = safe(s.impact_score, '0');
  const type      = safe(s.signal_type);
  const version   = parseInt(s.version || 1, 10);
  const status    = s.signal_status === 'NEW' ? '🆕 NEW' : `🔄 v${version}`;
  const rival     = s.competitor_flag ? ' ⚠️ *COMPETITOR*' : '';
  const urgent    = s.is_urgent ? ' 🔴 *URGENT*' : '';
  const lvlEmoji  = s.impact_level === 'HIGH' ? '🚨' : '🟡';
  const url       = safe(s.url, 'https://clinicaltrials.gov');

  return {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text:
        `${lvlEmoji} *${index + 1}. ${drug}* — ${indication} ${status}${rival}${urgent}\n` +
        `> Sponsor: *${sponsor}* | Type: \`${type}\` | Score: *${score}/10*\n` +
        `> ${safe(s.ai_summary, 'No summary available')}\n` +
        `> 🎯 _Action: ${safe(s.recommended_action, 'Monitor')}_`
    },
    accessory: {
      type: 'button',
      text: { type: 'plain_text', text: '🔗 View Source', emoji: true },
      url,
      action_id: `view_source_${index}`
    }
  };
}

// ─── Safe arrays ──────────────────────────────────────────
const highSignals    = Array.isArray(d.highSignals)    ? d.highSignals    : [];
const medSignals     = Array.isArray(d.medSignals)     ? d.medSignals     : [];
const heatmap        = Array.isArray(d.heatmap)        ? d.heatmap        : [];
const competitorIntel = Array.isArray(d.competitorIntel) ? d.competitorIntel : [];

// ─── Trend delta display ──────────────────────────────────
const trendDelta     = d.trendDelta || 0;
const trendDisplay   = `${trendDelta > 0 ? '+' : ''}${trendDelta} signals (${safe(d.trendPct, 'N/A')}%)`;

// ─── BUILD BLOCKS ─────────────────────────────────────────
const blocks = [];

// HEADER
blocks.push({
  type: 'header',
  text: {
    type: 'plain_text',
    text: `📋 OncoWatch Daily Digest — ${safe(d.today)}`,
    emoji: true
  }
});

// METRICS ROW 1
blocks.push({
  type: 'section',
  fields: [
    { type: 'mrkdwn', text: `${safe(d.riskEmoji, '⚪')} *Risk Level*\n${safe(d.riskLevel)}` },
    { type: 'mrkdwn', text: `📊 *Total Signals (24h)*\n${safe(d.total24h, '0')}` },
    { type: 'mrkdwn', text: `🚨 *HIGH Impact*\n${safe(d.highCount, '0')}` },
    { type: 'mrkdwn', text: `🟡 *MED Impact*\n${safe(d.medCount, '0')}` },
    { type: 'mrkdwn', text: `🆕 *New Signals*\n${safe(d.newCount, '0')}` },
    { type: 'mrkdwn', text: `⚠️ *Competitor Hits*\n${safe(d.competitorCount, '0')}` }
  ]
});

// METRICS ROW 2
blocks.push({
  type: 'section',
  fields: [
    { type: 'mrkdwn', text: `${safe(d.trendArrow, '➡️')} *vs Yesterday*\n${trendDisplay}` },
    { type: 'mrkdwn', text: `📅 *7-day HIGH total*\n${safe(d.weekHighCount, '0')}` },
    { type: 'mrkdwn', text: `⭐ *Avg Score*\n${safe(d.avgScore, '0')}/10` },
    { type: 'mrkdwn', text: `🔥 *Peak Score*\n${safe(d.maxScore, '0')}/10` }
  ]
});

blocks.push(divider());

// AI EXECUTIVE SUMMARY
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `🤖 *AI Executive Summary*\n\n${execSummary}`
  }
});
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `${safe(d.riskEmoji, '⚪')} *Risk Assessment:* ${safe(d.riskReason)}`
  }
});
blocks.push(divider());

// HIGH IMPACT SIGNALS
if (highSignals.length > 0) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `🚨 *HIGH IMPACT SIGNALS (${highSignals.length})*` }
  });
  highSignals.forEach((s, i) => {
    blocks.push(signalBlock(s, i));
    blocks.push(divider());
  });
}

// MED IMPACT SIGNALS
if (medSignals.length > 0) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `🟡 *MED IMPACT SIGNALS (top 6 of ${medSignals.length})*` }
  });
  medSignals.slice(0, 6).forEach((s, i) => {
    blocks.push(signalBlock(s, i));
    blocks.push(divider());
  });
  if (medSignals.length > 6) {
    blocks.push({
      type: 'section',
      text: {
        type: 'mrkdwn',
        text: `_...${medSignals.length - 6} more MED signals not shown. Query DB for full list._`
      }
    });
    blocks.push(divider());
  }
}

// INDICATION HEATMAP
if (heatmap.length > 0) {
  const hmText = heatmap.slice(0, 6).map(h =>
    `• *${safe(h.indication)}*: ${safe(h.total_signals)} signals ` +
    `(🚨${safe(h.high_count, '0')} 🟡${safe(h.med_count, '0')}) ` +
    `| avg score: ${safe(h.avg_score, 'N/A')} ` +
    `| competitor hits: ${safe(h.competitor_signals, '0')}`
  ).join('\n');

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `🗺️ *Indication Heatmap (24h)*\n\n${hmText}` }
  });
  blocks.push(divider());
}

// COMPETITOR INTELLIGENCE
if (competitorIntel.length > 0) {
  const ciText = competitorIntel.slice(0, 5).map((c, i) =>
    `${i + 1}. *${safe(c.key_drug || c.drug_name)}* (${safe(c.sponsor)})\n` +
    `   Indication: ${safe(c.key_indication)} | Signals: ${safe(c.signal_count)} | ` +
    `Peak Score: ${safe(c.peak_score, 'N/A')} | Types: ${safe(c.signal_types)}`
  ).join('\n\n');

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `🕵️ *7-Day Competitor Radar*\n\n${ciText}` }
  });
  blocks.push(divider());
}

// SIGNAL TYPE + SOURCE BREAKDOWN
blocks.push({
  type: 'section',
  fields: [
    { type: 'mrkdwn', text: `📁 *Signal Types*\n\`${safe(d.typeBreakdownStr, 'N/A')}\`` },
    { type: 'mrkdwn', text: `🌐 *Top Sources*\n${safe(d.sourceBreakdownStr, 'N/A')}` }
  ]
});
blocks.push({
  type: 'section',
  text: {
    type: 'mrkdwn',
    text: `💊 *Most Active Drugs (24h)*: ${safe(d.topDrugs, 'N/A')}`
  }
});
blocks.push(divider());

// FOOTER
blocks.push({
  type: 'context',
  elements: [
    {
      type: 'mrkdwn',
      text:
        `_OncoWatch Automated CI System | Generated: ${safe(d.now)} | ` +
        `Updated signals: ${safe(d.updatedCount, '0')} | ` +
        `LOW suppressed: ${safe(d.lowCount, '0')} | ` +
        `Scoring Engine v1_`
    }
  ]
});

return [{
  json: {
    blocks,
    riskLevel:      d.riskLevel,
    riskColor,
    highCount:      d.highCount,
    total24h:       d.total24h,
    today:          d.today,
    execSummary,
    competitorIntel,
    heatmap
  }
}];

const d = $('Compute Analytics').first().json;

const headers = [
  'date','drug','indication','sponsor','impact_level',
  'impact_score','signal_type','competitor_flag','signal_status',
  'version','source','url','ai_summary','recommended_action','first_seen_at'
].join(',');

const rows = d.signals24h.map(s => [
  d.today,
  `"${(s.key_drug || s.drug_name || '').replace(/"/g, '""')}"`,
  `"${(s.key_indication || '').replace(/"/g, '""')}"`,
  `"${(s.sponsor || '').replace(/"/g, '""')}"`,
  s.impact_level,
  s.impact_score,
  s.signal_type,
  s.competitor_flag ? 'YES' : 'NO',
  s.signal_status,
  s.version,
  s.source,
  `"${(s.url || '').replace(/"/g, '""')}"`,
  `"${(s.ai_summary || '').replace(/"/g, '""')}"`,
  `"${(s.recommended_action || '').replace(/"/g, '""')}"`,
  s.first_seen_at
].join(','));

const csv = [headers, ...rows].join('\n');
const filename = `oncowatch_digest_${d.today}.csv`;

return [{ json: { csv, filename, rowCount: rows.length } }];

const d = $('Compute Analytics').first().json;

// ─── Sanitizer ────────────────────────────────────────────
const clean = (v, fallback = 'N/A') => {
  if (v === null || v === undefined) return fallback;
  return String(v)
    .replace(/[\\"]/g, ' ')
    .replace(/[\n\r\t]/g, ' ')
    .replace(/[\u0000-\u001F\u007F-\u009F]/g, '')
    .replace(/\s+/g, ' ')
    .trim() || fallback;
};

// ─── Signal Intelligence Lines ────────────────────────────
const highLines = (d.highSignals || []).slice(0, 5).map((s, i) =>
  `${i+1}. ${clean(s.key_drug || s.drug_name)} (${clean(s.sponsor)}) ` +
  `in ${clean(s.key_indication)} via ${clean(s.signal_type)}. ` +
  `Summary: ${clean(s.ai_summary)}. Recommended action: ${clean(s.recommended_action)}.`
).join(' || ') || 'No HIGH signals today';

const medLines = (d.medSignals || []).slice(0, 3).map((s, i) =>
  `${i+1}. ${clean(s.key_drug || s.drug_name)} (${clean(s.sponsor)}) ` +
  `in ${clean(s.key_indication)}.`
).join(' || ') || 'No MED signals today';

const competitorLines = (d.competitorIntel || []).slice(0, 3).map((c, i) =>
  `${i+1}. ${clean(c.key_drug || c.drug_name)} by ${clean(c.sponsor)} ` +
  `targeting ${clean(c.key_indication)} — ${clean(c.signal_count)} signals detected.`
).join(' || ') || 'No active competitor threats';

const heatmapLines = (d.heatmap || []).slice(0, 5).map(h =>
  `${clean(h.indication)}: ${clean(h.total_signals)} signals ` +
  `(HIGH:${clean(h.high_count)} MED:${clean(h.med_count)} Competitor:${clean(h.competitor_signals)})`
).join(' | ') || 'No heatmap data';

// ─── System Prompt ────────────────────────────────────────
const systemContent =
  'You are OncoWatch AI, an elite oncology competitive intelligence analyst embedded at Novartis Global Medical Affairs. ' +
  'Your audience is C-suite: VP Medical Affairs, Senior BD Directors, and Global Oncology Strategy Leads who make million-dollar portfolio decisions daily. ' +
  'Constraints: Respond in EXACTLY 5 sentences. Zero preamble. Zero filler. ' +
  'Begin your response directly with the most critical finding. ' +
  'Every sentence must carry strategic weight. ' +
  'Style: McKinsey precision meets clinical oncology expertise. ' +
  'Never speculate — only synthesize the data provided.';

// ─── User Prompt ──────────────────────────────────────────
const userContent =
  `ONCOWATCH DAILY INTELLIGENCE BRIEF - ${clean(d.today)} ` +

  `RISK STATUS: ${clean(d.riskLevel)} - ${clean(d.riskReason)}. ` +

  `24H SIGNAL METRICS: ` +
  `${clean(d.total24h)} total signals processed. ` +
  `HIGH impact: ${clean(d.highCount)}. ` +
  `MED impact: ${clean(d.medCount)}. ` +
  `LOW impact: ${clean(d.lowCount)}. ` +
  `New signals: ${clean(d.newCount)}. ` +
  `Updated signals: ${clean(d.updatedCount)}. ` +
  `Active competitor hits: ${clean(d.competitorCount)}. ` +
  `Volume trend vs yesterday: ${clean(d.trendArrow)} ${clean(d.trendDelta)} signals (${clean(d.trendPct)}%). ` +
  `7-day HIGH signal total: ${clean(d.weekHighCount)}. ` +

  `HIGH IMPACT SIGNALS (requires immediate attention): ${highLines}. ` +

  `MED IMPACT SIGNALS (monitor closely): ${medLines}. ` +

  `ACTIVE COMPETITOR THREATS (7-day radar): ${competitorLines}. ` +

  `THERAPEUTIC INDICATION HEATMAP (24h hotspots): ${heatmapLines}. ` +

  `INTELLIGENCE CONTEXT: ` +
  `Most active drugs: ${clean(d.topDrugs)}. ` +
  `Signal type distribution: ${clean(d.typeBreakdownStr)}. ` +
  `Intelligence sources: ${clean(d.sourceBreakdownStr)}. ` +

  `YOUR TASK - Write exactly 5 sentences in this order: ` +
  `Sentence 1: State the overall oncology competitive landscape today in one precise sentence including volume and risk level. ` +
  `Sentence 2: Name the single most urgent competitive threat - identify the exact drug, sponsor, indication, and explain why it is strategically dangerous for Novartis right now. ` +
  `Sentence 3: Identify which therapeutic indication demands immediate Novartis strategic attention, citing specific signal evidence and clinical rationale. ` +
  `Sentence 4: Deliver one specific, time-bound, actionable recommendation for the Medical Affairs or BD team to execute within the next 7 days. ` +
  `Sentence 5: Conclude with the overall risk posture score, and name the single most important signal or development to monitor in the next 48 hours.`;

// ─── Return object directly (no JSON.stringify) ───────────
return [{
  json: {
    requestBody: {
      model: 'google/gemini-2.0-flash-001',
      messages: [
        { role: 'system', content: systemContent },
        { role: 'user',   content: userContent   }
      ],
